{
var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var strength = GetFloat(parameters, "strength", 0.5f);
var radius = Math.Max(0.01f, GetFloat(parameters, "radius", 0.7f));
var feather = Math.Max(0.001f, GetFloat(parameters, "feather", 0.3f));
var shape = GetChoice(parameters, "shape", "circle");
var centerX = GetFloat(parameters, "centerX", 0.5f);
var centerY = GetFloat(parameters, "centerY", 0.5f);
var invert = GetBool(parameters, "invert", false);
var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

var size = context.TileSize;
var result = new PixelBuffer(size, size);

var cx = centerX * size;
var cy = centerY * size;
var maxDist = shape == "circle"
    ? size * 0.5f * radius
    : MathF.Max(cx, cy) * radius;

result.ParallelForEachPixel((x, y) =>
{
    var (r, g, b, a) = src.GetPixel(x, y);

    float dist;
    if (shape == "rectangle")
    {
        var dx = MathF.Abs(x - cx) / MathF.Max(cx, 1f);
        var dy = MathF.Abs(y - cy) / MathF.Max(cy, 1f);
        dist = MathF.Max(dx, dy);
    }
    else
    {
        dist = MathF.Sqrt((x - cx) * (x - cx) + (y - cy) * (y - cy)) / maxDist;
    }

    // Smoothstep falloff
    var vignette = 1f - SmoothStep(1f - feather, 1f, dist);
    vignette = 1f - (1f - vignette) * strength;

    if (invert) vignette = 1f - vignette;

    result.SetPixel(x, y,
        Math.Clamp(r * vignette, 0f, 1f),
        Math.Clamp(g * vignette, 0f, 1f),
        Math.Clamp(b * vignette, 0f, 1f),
        preserveAlpha ? a : vignette);
});

return result;
}
